import { readFileSync } from "node:fs";
import { join } from "node:path";
import { describe, expect, it } from "vitest";
import { blockingNote } from "../output.js";
const SRC_ROOT = join(__dirname, "..", "..", "src");
/**
 * Commands that open Studio and stay alive indefinitely waiting for a user
 * action MUST warn agents about the blocking contract, or a foreground call
 * hangs the conversation until the user acts (see the startDataset hang in
 * Lore thread th_033SqGbbXmzunB2hC72PN0).
 *
 * The warning lives in two places, both verified here:
 *
 *   1. Runtime stderr banner - emitted ONCE at the shared chokepoint,
 *      `startEventPoller` in openStudioTo.ts. Every blocking command funnels
 *      through that poller (see blockingMonitorOptIn.test.ts, which pins that
 *      they all call openStudioTo and await `result.done`), so centralizing
 *      the emit there means a new blocking command inherits the banner for
 *      free and the coverage gap cannot recur.
 *   2. Usage output - each command threads `blockingNote(...)` through its
 *      `usageNote`, so a no-args probe teaches the contract before the command
 *      is ever run for real. This stays per-command because the usage text and
 *      args differ.
 *
 * Bounded, intentionally-foreground commands (login.js, waitForTrace.js) are
 * exempt: their flows block on them deliberately with explicit timeouts, and
 * login.js prints its own factual note.
 */
const BLOCKING_COMMAND_FILES = [
    "commands/startDataset.ts",
    "commands/openTracePlan.ts",
    "commands/startTemplatePreview.ts",
    "commands/openExperiments.ts",
    "commands/openDatasetExperiments.ts",
];
function readSrc(relPath) {
    return readFileSync(join(SRC_ROOT, relPath), "utf-8");
}
/** Slice a source file from a named declaration to the next top-level one. */
function _functionBody(src, signature) {
    const start = src.indexOf(signature);
    if (start === -1) {
        return "";
    }
    const rest = src.slice(start + signature.length);
    const next = rest.search(/\n(?:export )?(?:async )?function /);
    return next === -1 ? rest : rest.slice(0, next);
}
describe("blocking-notice contract", () => {
    for (const file of BLOCKING_COMMAND_FILES) {
        it(`${file}: surfaces the blocking note in usage output`, () => {
            const src = readSrc(file);
            expect(src.includes("blockingNote("), `${file} must surface blockingNote() in its usage output (usageNote ` +
                `on parseArgs/positionalArgs) so an agent probing the command with ` +
                `no args learns the blocking contract before running it for real.`).toBe(true);
        });
    }
    it("blockingNote spells out the contract and the fix", () => {
        const note = blockingNote("the user clicks Done in Studio");
        expect(note).toContain("BLOCKING");
        expect(note).toContain("does not exit until the user clicks Done in Studio");
        expect(note).toContain("run it in the background");
    });
});
